async function main() {
  console.log("Seeding training templates with structured sections...");

  for (const template of trainingTemplates) {
    const data = {
      title: template.title,
      trainingType: template.trainingType as any,
      description: template.description,
      legalBasis: template.legalBasis,
      targetGroup: template.targetGroup,
      content: template.content,
      sections: JSON.parse(JSON.stringify(template.sections)),
      recurrenceMonths: template.recurrenceMonths,
      durationMinutes: template.durationMinutes,
      sortOrder: template.sortOrder,
    };

    const existing = await prisma.trainingTemplate.findFirst({
      where: { title: template.title },
    });

    if (existing) {
      await prisma.trainingTemplate.update({
        where: { id: existing.id },
        data,
      });
    } else {
      await prisma.trainingTemplate.create({ data });
    }
    console.log(`  ✓ ${template.title} (${template.sections.length} Abschnitte)`);
  }

  console.log(`\nDone! ${trainingTemplates.length} training templates seeded.`);
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect());
